import React from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Users } from 'lucide-react';

export default function Network() {
  const navigate = useNavigate();

  return (
    <div className="min-h-screen bg-gray-50 p-4">
      <button onClick={() => navigate('/dashboard')} className="flex items-center gap-2 text-blue-600 mb-8">
        <ArrowLeft className="w-5 h-5" /> Back
      </button>
      <div className="max-w-4xl mx-auto">
        <h1 className="text-3xl font-bold text-gray-900 mb-8">Alumni Network</h1>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {[1, 2, 3, 4, 5, 6].map((i) => (
            <div key={i} className="bg-white rounded-lg shadow p-6">
              <Users className="w-8 h-8 text-blue-600 mb-4" />
              <h3 className="font-semibold text-gray-900">Alumni {i}</h3>
              <p className="text-gray-600 text-sm">Class of 2020</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
